def to_str_tokens(tokenizer: tr.AutoTokenizer, prompt: str | list[str]) -> str:
    if isinstance(prompt, str):
        prompt = [prompt]
    return [tokenizer.decode(i) for p in prompt for i in tokenizer.encode(p, add_special_tokens=False)]

